final:
module RefModule (
  input A,
  input B,
  input SEL,
  output Y
);

  wire NOT_SEL;
  wire AND1;
  wire AND2;
  wire OR;

  wire __NOT_SEL_tmp = ~SEL;
  assign NOT_SEL = __NOT_SEL_tmp;
  assign AND1 = A & NOT_SEL;
  assign AND2 = B & SEL;
  assign OR = AND1 | AND2;

  assign Y = OR;

endmodule
